import{_ as t,o as a,c as o,a2 as s}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"Aider — Core Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/aider/architecture.md","filePath":"research/agents/aider/architecture.md"}'),n={name:"research/agents/aider/architecture.md"};function i(r,e,l,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="aider-—-core-architecture" tabindex="-1">Aider — Core Architecture <a class="header-anchor" href="#aider-—-core-architecture" aria-label="Permalink to &quot;Aider — Core Architecture&quot;">​</a></h1><h2 id="high-level-design" tabindex="-1">High-Level Design <a class="header-anchor" href="#high-level-design" aria-label="Permalink to &quot;High-Level Design&quot;">​</a></h2><p>Aider is a Python application (~30k lines) structured around a central <code>Coder</code> class hierarchy that mediates between the user, LLMs, the file system, and git. The architecture is designed around a key insight: <strong>different LLMs need different strategies for expressing code edits</strong>, so the edit format is a pluggable, first-class abstraction.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>aider/</span></span>
<span class="line"><span>├── main.py                  # CLI entry point, argument parsing</span></span>
<span class="line"><span>├── coders/                  # Core: the Coder class hierarchy</span></span>
<span class="line"><span>│   ├── base_coder.py        # Base class — chat loop, context assembly</span></span>
<span class="line"><span>│   ├── editblock_coder.py   # &quot;diff&quot; edit format (search/replace blocks)</span></span>
<span class="line"><span>│   ├── wholefile_coder.py   # &quot;whole&quot; edit format (full file replacement)</span></span>
<span class="line"><span>│   ├── udiff_coder.py       # &quot;udiff&quot; edit format (unified diff)</span></span>
<span class="line"><span>│   ├── architect_coder.py   # Architect mode (two-model orchestration)</span></span>
<span class="line"><span>│   ├── editor_editblock_coder.py  # Editor sub-coder for architect mode</span></span>
<span class="line"><span>│   ├── editor_whole_coder.py      # Editor sub-coder (whole format)</span></span>
<span class="line"><span>│   ├── *_prompts.py         # System prompts for each edit format</span></span>
<span class="line"><span>│   └── __init__.py          # Registry of all coder types</span></span>
<span class="line"><span>├── repomap.py               # Tree-sitter repo map generation</span></span>
<span class="line"><span>├── repo.py                  # Git repository abstraction</span></span>
<span class="line"><span>├── commands.py              # Slash-command handling (/add, /drop, /undo, etc.)</span></span>
<span class="line"><span>├── io.py                    # Terminal I/O, pretty printing, input handling</span></span>
<span class="line"><span>├── models.py                # Model configuration, routing, capabilities</span></span>
<span class="line"><span>├── sendchat.py              # LLM API interaction (via litellm)</span></span>
<span class="line"><span>├── voice.py                 # Voice-to-text via Whisper</span></span>
<span class="line"><span>├── watch.py                 # File watcher for IDE integration</span></span>
<span class="line"><span>├── linter.py                # Built-in and custom linting</span></span>
<span class="line"><span>├── prompts.py               # Shared prompt templates</span></span>
<span class="line"><span>├── queries/                 # Tree-sitter query files (.scm) per language</span></span>
<span class="line"><span>└── website/                 # Docs site (aider.chat)</span></span></code></pre></div><h2 id="the-coder-class-hierarchy" tabindex="-1">The Coder Class Hierarchy <a class="header-anchor" href="#the-coder-class-hierarchy" aria-label="Permalink to &quot;The Coder Class Hierarchy&quot;">​</a></h2><p>The heart of Aider is the <code>Coder</code> base class in <code>base_coder.py</code>. This is a large (~2000 line) class that handles:</p><ul><li><strong>Chat history management</strong> — maintaining message lists for the LLM</li><li><strong>Context assembly</strong> — combining repo-map, added files, and user messages into prompts</li><li><strong>Response parsing</strong> — extracting file edits from LLM responses</li><li><strong>File application</strong> — writing edits to disk</li><li><strong>Git integration</strong> — auto-committing changes</li><li><strong>Lint/test cycle</strong> — running linters and tests after edits</li></ul><p>Each <strong>edit format</strong> is implemented as a subclass:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Coder (base_coder.py)</span></span>
<span class="line"><span>├── EditBlockCoder        # &quot;diff&quot; format — search/replace blocks</span></span>
<span class="line"><span>├── WholeFileCoder        # &quot;whole&quot; format — full file output</span></span>
<span class="line"><span>├── UnifiedDiffCoder      # &quot;udiff&quot; format — unified diffs</span></span>
<span class="line"><span>├── ArchitectCoder        # &quot;architect&quot; mode — two-model pipeline</span></span>
<span class="line"><span>├── EditBlockFuncCoder    # &quot;diff-func&quot; — function-call variant</span></span>
<span class="line"><span>└── WholeFileFuncCoder    # &quot;whole-func&quot; — function-call variant</span></span></code></pre></div><p>The <code>Coder.create()</code> factory method selects the right subclass based on the model&#39;s configured edit format:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#FAB387;font-style:italic;">@classmethod</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> create</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">cls</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> main_model</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> edit_format</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> io</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> **</span><span style="color:#EBA0AC;font-style:italic;">kwargs</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # Looks up the appropriate Coder subclass for the edit_format</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # e.g., &quot;diff&quot; → EditBlockCoder, &quot;whole&quot; → WholeFileCoder</span></span></code></pre></div><h2 id="model-routing-models-py" tabindex="-1">Model Routing (<code>models.py</code>) <a class="header-anchor" href="#model-routing-models-py" aria-label="Permalink to &quot;Model Routing (\`models.py\`)&quot;">​</a></h2><p>Aider uses <strong>litellm</strong> as its LLM abstraction layer, allowing it to connect to virtually any provider. The <code>models.py</code> module handles:</p><ol><li><strong>Model identification</strong> — parsing model names (e.g., <code>sonnet</code>, <code>o3-mini</code>, <code>deepseek/deepseek-chat</code>)</li><li><strong>Capability detection</strong> — determining if a model supports vision, function calling, streaming, thinking tokens</li><li><strong>Edit format selection</strong> — choosing the optimal edit format per model: <ul><li>Claude models → <code>diff</code></li><li>Gemini models → <code>diff-fenced</code> (Gemini struggles with standard fence formatting)</li><li>GPT-3.5 → <code>whole</code> (too weak for diff formats)</li><li>o1/o3 reasoning models → <code>architect</code> mode recommended</li><li>DeepSeek → <code>diff</code></li></ul></li><li><strong>Weak model selection</strong> — choosing a cheaper model for tasks like commit messages</li><li><strong>Token limit management</strong> — knowing context windows and pricing per model</li></ol><p>Model metadata is configured through a combination of:</p><ul><li>Built-in defaults in <code>models.py</code></li><li>A <code>model-metadata.json</code> file</li><li>User overrides via <code>--model-metadata-file</code></li></ul><h2 id="git-integration-repo-py" tabindex="-1">Git Integration (<code>repo.py</code>) <a class="header-anchor" href="#git-integration-repo-py" aria-label="Permalink to &quot;Git Integration (\`repo.py\`)&quot;">​</a></h2><p>The <code>GitRepo</code> class wraps git operations:</p><ul><li><strong>Auto-commit</strong>: Every edit is committed with a descriptive message generated by the &quot;weak model&quot;</li><li><strong>Dirty file protection</strong>: Uncommitted changes are committed separately before AI edits begin</li><li><strong>Undo</strong>: <code>/undo</code> reverts the last AI commit</li><li><strong>Diff tracking</strong>: Shows what changed after each interaction</li><li><strong>Attribution</strong>: Commits by aider are marked with <code>(aider)</code> in the author name</li></ul><h2 id="commands-system-commands-py" tabindex="-1">Commands System (<code>commands.py</code>) <a class="header-anchor" href="#commands-system-commands-py" aria-label="Permalink to &quot;Commands System (\`commands.py\`)&quot;">​</a></h2><p>Aider provides ~30 slash commands:</p><table tabindex="0"><thead><tr><th>Command</th><th>Purpose</th></tr></thead><tbody><tr><td><code>/add &lt;file&gt;</code></td><td>Add file to chat context</td></tr><tr><td><code>/drop &lt;file&gt;</code></td><td>Remove file from context</td></tr><tr><td><code>/ask &lt;question&gt;</code></td><td>Ask without editing</td></tr><tr><td><code>/code &lt;request&gt;</code></td><td>Request code changes</td></tr><tr><td><code>/architect &lt;request&gt;</code></td><td>Use architect mode</td></tr><tr><td><code>/undo</code></td><td>Revert last AI change</td></tr><tr><td><code>/diff</code></td><td>Show recent changes</td></tr><tr><td><code>/run &lt;cmd&gt;</code></td><td>Run shell command, optionally share output</td></tr><tr><td><code>/test &lt;cmd&gt;</code></td><td>Run tests, auto-fix failures</td></tr><tr><td><code>/lint</code></td><td>Run linter on changed files</td></tr><tr><td><code>/voice</code></td><td>Voice input via Whisper</td></tr><tr><td><code>/model &lt;name&gt;</code></td><td>Switch LLM</td></tr><tr><td><code>/tokens</code></td><td>Show token usage</td></tr><tr><td><code>/clear</code></td><td>Clear chat history</td></tr><tr><td><code>/map</code></td><td>Show current repo map</td></tr><tr><td><code>/map-refresh</code></td><td>Force repo map refresh</td></tr></tbody></table><h2 id="terminal-i-o-io-py" tabindex="-1">Terminal I/O (<code>io.py</code>) <a class="header-anchor" href="#terminal-i-o-io-py" aria-label="Permalink to &quot;Terminal I/O (\`io.py\`)&quot;">​</a></h2><p>Aider uses <code>prompt_toolkit</code> for rich terminal interaction:</p><ul><li>Syntax-highlighted code display</li><li>Markdown rendering of LLM responses</li><li>Tab completion for commands and file paths</li><li>Streaming output with live diffs</li><li>Color-coded display (user input, AI output, tool output, errors)</li></ul><h2 id="watch-mode-watch-py" tabindex="-1">Watch Mode (<code>watch.py</code>) <a class="header-anchor" href="#watch-mode-watch-py" aria-label="Permalink to &quot;Watch Mode (\`watch.py\`)&quot;">​</a></h2><p>The <code>--watch-files</code> mode enables IDE integration:</p><ul><li>Monitors all repo files for changes</li><li>Scans for special <code>AI</code> / <code>AI!</code> / <code>AI?</code> comments</li><li>Triggers code edits or questions automatically</li><li>Allows users to work in their preferred editor while aider runs in a terminal</li></ul><h2 id="configuration-system" tabindex="-1">Configuration System <a class="header-anchor" href="#configuration-system" aria-label="Permalink to &quot;Configuration System&quot;">​</a></h2><p>Aider supports configuration through multiple layers (in priority order):</p><ol><li>Command-line arguments</li><li><code>.aider.conf.yml</code> in the repo root</li><li><code>.aider.conf.yml</code> in the home directory</li><li>Environment variables (<code>AIDER_xxx</code>)</li><li><code>.env</code> file</li></ol>`,31)])])}const u=t(n,[["render",i]]);export{m as __pageData,u as default};
